<?php require_once __DIR__.'/../includes/app-layout.php'; $wallet=bos_page_start('Beyond Sell','Beyond Sell','Buy, sell, auction and earn.'); $listings=[]; try{$listings=beyond_db()->query("SELECT id,title,item_type,listing_type,price_cash,price_bits,currency,status FROM listings WHERE status='active' ORDER BY created_at DESC LIMIT 12")->fetchAll();}catch(Throwable $e){} if(!$listings)$listings=[['id'=>1,'title'=>'Galaxy Wallpaper Pack','item_type'=>'digital','listing_type'=>'buy_now','price_cash'=>1.99,'price_bits'=>50,'currency'=>'USD','status'=>'active'],['id'=>2,'title'=>'Beyond OS Hoodie','item_type'=>'physical','listing_type'=>'buy_now','price_cash'=>49.99,'price_bits'=>null,'currency'=>'USD','status'=>'active'],['id'=>3,'title'=>'Logo Design Session','item_type'=>'service','listing_type'=>'auction','price_cash'=>25,'price_bits'=>null,'currency'=>'USD','status'=>'active']]; ?>
<main class="bos-main"><section class="bos-hero"><span class="bos-kicker">Beyond Sell 2.1 Beta</span><h1>Buy. Sell. Auction.</h1><p>Digital goods, physical products, services and creator work paid with bit$ or Stripe Checkout.</p><div class="bos-actions"><a class="bos-btn" href="create.php">List an item</a><a class="bos-btn secondary" href="orders.php">My orders</a></div></section><section class="bos-section"><h2>Featured listings</h2><div class="bos-grid"><?php foreach($listings as $l): ?><a class="bos-card" href="listing.php?id=<?=intval($l['id'])?>"><span class="bos-card-icon"><?=e($l['item_type']==='digital'?'⬇':($l['item_type']==='physical'?'📦':'🛠'))?></span><div><strong><?=e($l['title'])?></strong><p><?=e(ucfirst($l['listing_type']))?> · <?=e(ucfirst($l['item_type']))?></p><p><?php if($l['price_bits']!==null):?><?=number_format((int)$l['price_bits'])?> bit$ <?php endif;?><?php if((float)$l['price_cash']>0):?><?=($l['price_bits']!==null?' or ':'')?>$<?=number_format((float)$l['price_cash'],2)?> <?=e($l['currency'])?><?php endif;?></p></div><span class="bos-card-status">View</span></a><?php endforeach;?></div></section></main><?php bos_page_end(); ?>
